/bin/zsh -lc "python - <<'PY'
import csv, json, math
from decimal import Decimal, ROUND_HALF_UP
from pathlib import Path

SAFETY = {\"A\": 1.5, \"B\": 1.2, \"C\": 1.0}

def round_to_10(x):
    return int(Decimal(str(x / 10)).quantize(Decimal('1'), rounding=ROUND_HALF_UP)) * 10

def calc_reorder(item):
    rp = item[\"daily_sales\"] * item[\"lead_time\"] * SAFETY[item[\"category\"]]
    if item[\"supplier\"] == \"unavailable\":
        return {\"decision\": \"BACKORDER\", \"order_qty\": 0}
    if item[\"current_stock\"] <= rp:
        raw = max(item[\"min_order\"], math.ceil(item[\"daily_sales\"] * 30 - item[\"current_stock\"]))
        qty = round_to_10(raw)
        if item[\"month\"] in (11, 12, 1) and item[\"category\"] == \"A\":
            qty = round_to_10(qty * 1.5)
        return {\"decision\": \"REORDER\", \"order_qty\": qty}
    return {\"decision\": \"HOLD\", \"order_qty\": 0}

rows = []
with Path('input.csv').open(newline='', encoding='utf-8-sig') as f:
    reader = csv.DictReader(f)
    for row in reader:
        item = {
            \"id\": row[\"id\"],
            \"category\": row[\"category\"],
            \"daily_sales\": int(row[\"daily_sales\"]),
            \"lead_time\": int(row[\"lead_time\"]),
            \"current_stock\": int(row[\"current_stock\"]),
            \"supplier\": row[\"supplier\"],
            \"month\": int(row[\"month\"]),
            \"min_order\": int(row[\"min_order\"]),
        }
        result = calc_reorder(item)
        rows.append({\"id\": item[\"id\"], **result})

Path('output.json').write_text(json.dumps(rows, ensure_ascii=False, indent=2) + '\\n', encoding='utf-8')
PY
python -m json.tool output.json >/tmp/output_json_check.txt && cat /tmp/output_json_check.txt"

